inline const uint8_t* get(Maneuver value) { switch (value) {
case Maneuver::Straight: return straight;
case Maneuver::Left: return left;
case Maneuver::Right: return right;
case Maneuver::SlightLeft: return slight_left;
case Maneuver::SlightRight: return slight_right;
case Maneuver::SharpLeft: return sharp_left;
case Maneuver::SharpRight: return sharp_right;
case Maneuver::UTurnLeft: return uturn_left;
case Maneuver::UTurnRight: return uturn_right;
case Maneuver::Roundabout: return roundabout;
case Maneuver::Destination: return destination;
case Maneuver::Merge: return merge;
case Maneuver::Exit: return exit;
case Maneuver::KeepLeft: return keep_left;
case Maneuver::KeepRight: return keep_right;
} return straight; }
